def is_perfect_square_of_two_primes(b):
    """ Returns true if and only if the input number is a perfect square of two distinct prime numbers, 
    otherwise, return false. """
    def is_prime(n):
        """Check if n is a prime number"""
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    sqrt_b = b**0.5
    if sqrt_b != int(sqrt_b):
        return False

    sqrt_b = int(sqrt_b)
    factors = []
    for i in range(2, sqrt_b+1):
        while b % i == 0 and is_prime(i):
            factors.append(i)
            b //= i

    return len(factors) == 2 and factors[0] != factors[1]

